const input = $input.first().json;
const item = input.message || input.body || input;
const textBody = item.text || item.caption || item.message?.text || '';

function findContact(obj) {
  if (!obj || typeof obj !== 'object') return null;
  const contact = obj.contact || obj.sender_contact || obj.from || obj.sender?.wa_id || '';
  if (typeof contact === 'string') {
    if (contact.includes('t.me/')) return contact.split('t.me/')[1];
    if (contact.startsWith('tg_id_')) return contact;
    if (contact.startsWith('@')) return contact;
    if (/^\d{7,15}$/.test(contact)) return 'tg_id_' + contact;
  }
  return null;
}

let sc = findContact(item) || findContact(input);
if (sc && !sc.startsWith('tg_id_')) {
  sc = sc.trim();
  if (!sc.startsWith('@')) sc = '@' + sc;
}

const sourceChatId = item.chatId || item.chat?.id || input.source_chat_id || '';

return [{ json: {
  ...item,
  platform: 'Telegram',
  sender_contact: sc || 'No_Username',
  final_contact: sc || 'No_Username',
  source_chat_id: sourceChatId,
  texto_limpio: textBody.trim(),
  looksValuable: textBody.length > 5
}}];

const input = $input.first().json;
const item = input.message || (input.messages && input.messages[0]) || input.body || input;
const textBody = item.text?.body || item.text || item.caption || item.body || '';

function getPhone(val) {
  if (!val) return null;
  let s = '';
  if (typeof val === 'object') {
    s = String(val.id || val.author || val.from || val.phone || val.number || val.wa_id || val.remoteJid || '');
  } else {
    s = String(val);
  }
  if (s.includes('@g.us') || s.includes('-')) return null;
  const digits = s.replace(/\D/g, '');
  return (digits.length >= 7 && digits.length <= 15) ? digits : null;
}

const sc = getPhone(item.author) || getPhone(item.from) || getPhone(item.sender) || getPhone(input.sender?.wa_id) || getPhone(input.contact) || "No disponible";
const sourceChatId = item.chat_id || item.chatId || input.source_chat_id || null;

return [{ json: {
  ...item,
  platform: "WhatsApp",
  sender_contact: sc,
  final_contact: sc,
  source_chat_id: sourceChatId,
  texto_limpio: String(textBody).trim(),
  looksValuable: String(textBody).length > 5
}}];

const results = [];
const HARD_BLOCK = new Set(["crypto", "binance", "casino", "usdt", "bitcoin", "wallet", "trading", "ganar dinero", "инди", "контент", "onlyfans", "вирт", "sugar baby", "sugar daddy", "anal", "masaje erotico", "ingles", "english"]);
const BANNED_PREFIXES = ["58", "57", "92", "91", "62", "244"];

function norm(v) { return String(v || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, ""); }

for (const item of $input.all()) {
  const data = item.json;
  const text = norm(data.texto_limpio);
  const sender = String(data.final_contact).replace(/\D/g, "");

  let rejectReason = null;
  if (BANNED_PREFIXES.some(p => sender.startsWith(p))) rejectReason = "prefix_banned";
  else if (HARD_BLOCK.has(text)) rejectReason = "hard_block_match";

  results.push({ json: { ...data, looksValuable: !rejectReason, reject_reason: rejectReason } });
}
return results;

const results = [];
const store = $getWorkflowStaticData('global');
if (!store.history) store.history = [];

const now = Date.now();
const TTL = 86400000;
store.history = store.history.filter(h => now - h.time < TTL);

for (const item of $input.all()) {
  const fp = String(item.json.texto_limpio).substring(0, 100);
  if (!store.history.some(h => h.fp === fp)) {
    store.history.push({ time: now, fp });
    results.push(item);
  }
}
return results;

// PARSE JSON v5.9 (METADATA PRESERVE ROBUST)
const input = $json;
const rawText = input.output || input.text || "";
const cleanText = rawText.replace(/```json|```/g, '').trim();

// RECUPERAR METADATA PERDIDA de Dedup Hash1 (el nodo inmediatamente anterior a la IA)
let prevItem = {};
try { prevItem = $items("Dedup Hash1")[0].json; } catch(e) {}

const platform = prevItem.platform || input.platform || "WhatsApp";
let contact = prevItem.final_contact || prevItem.sender_contact || input.sender_contact || input.final_contact || "Desconocido";

// Si el contacto es un ID de grupo, lo marcamos como Desconocido
if (String(contact).includes('@g.us') || String(contact).length > 20) { contact = "Desconocido"; } else if (/^\d{7,15}$/.test(String(contact))) { contact = '+' + contact; } 

let parsed = {};
try {
  if (cleanText) parsed = JSON.parse(cleanText);
} catch (e) {
  const catMatch = cleanText.match(/"category"\s*:\s*"(.*?)"/i);
  if (catMatch) parsed.category = catMatch[1];
}

const originalTextoLimpio = prevItem.texto_limpio || "";
const lowerRaw = originalTextoLimpio.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
const isJobish = lowerRaw.includes("busco") || lowerRaw.includes("disponible") || lowerRaw.length > 20;

const finalData = {
  platform,
  contact,
  texto_limpio: originalTextoLimpio,
  source_chat_id: prevItem.source_chat_id || input.source_chat_id || "0",
  city: parsed.city || "Global",
  budget: parsed.budget || "Negociable",
  category: (parsed.category || (isJobish ? "evento" : "trash")).toLowerCase(),
  text_es: parsed.text_es || originalTextoLimpio || "Sin descripción",
  title_es: parsed.title_es || (lowerRaw ? lowerRaw.substring(0, 40) : "Nuevo Lead"),
  text_en: parsed.text_en || "",
  title_en: parsed.title_en || "",
  text_ru: parsed.text_ru || "",
  title_ru: parsed.title_ru || "",
  text_pt: parsed.text_pt || "",
  title_pt: parsed.title_pt || "",
  trash: parsed.trash === true || (parsed.category === 'trash' && !isJobish) || false
};

const highValueKeywords = ["mansour", "ibiza", "lio", "pacha", "monaco", "viena", "dubai", "manila"];
if (highValueKeywords.some(kw => lowerRaw.includes(kw))) {
  finalData.trash = false;
  if (finalData.category === 'trash') finalData.category = "evento";
}

return [{ json: finalData }];

const text = $json.texto_limpio || "";
const results = [];
// Regex flexible para capturar chat.whatsapp.com con su ID
const linkRegex = /(?:https?:\/\/)?chat\.whatsapp\.com\/[a-zA-Z0-9_-]{20,30}/g;
const matches = text.match(linkRegex);

if (matches) {
  for (let match of matches) {
    if (!match.startsWith("http")) {
      match = "https://" + match;
    }
    results.push({ 
      json: { 
        link: match, 
        platform: $json.platform, 
        source: $json.source_chat_id 
      } 
    });
  }
}
return results;
